function distanceKm(lat1, lon1, lat2, lon2) {
  const R = 6371;

  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;

  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(lat1 * Math.PI / 180) *
    Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon / 2) ** 2;

  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function json(data, status = 200) {
  return new Response(JSON.stringify(data, null, 2), {
    status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    }
  });
}

// =====================================================
// 가까운 농협 찾기 함수
// =====================================================
function findNearestBranches(lat, lon, limit = 5) {
  return BRANCHES
    .map((b) => {
      const dist = distanceKm(
        Number(lat),
        Number(lon),
        Number(b.lat),
        Number(b.lon)
      );

      return {
        ...b,
        distance_km: Number(dist.toFixed(2)),
        kakao_route_url: `https://map.kakao.com/link/to/${encodeURIComponent(b.name)},${b.lat},${b.lon}`
      };
    })
    .sort((a, b) => a.distance_km - b.distance_km)
    .slice(0, limit);
}

function normalizeSearchText(value) {
  return String(value || "")
    .trim()
    .replace(/\s+/g, "")
    .toLowerCase();
}

function searchBranchesByKeyword(keyword, limit = 20) {
  const q = normalizeSearchText(keyword);

  if (!q) {
    return [];
  }

  return BRANCHES
    .filter(function (item) {
      const name = normalizeSearchText(item.name);
      const branchName = normalizeSearchText(item.branch_name);
      const roadAddress = normalizeSearchText(item.road_address);
      const jibunAddress = normalizeSearchText(item.jibun_address);
      const finalAddress = normalizeSearchText(item.final_address);

      return (
        name.includes(q) ||
        branchName.includes(q) ||
        roadAddress.includes(q) ||
        jibunAddress.includes(q) ||
        finalAddress.includes(q)
      );
    })
    .slice(0, limit)
    .map(function (item) {
      return {
        ...item,
        phone: String(item.phone || "").trim(),
        kakao_route_url:
          "https://map.kakao.com/link/to/" +
          encodeURIComponent(item.name || item.branch_name || "쉼터") +
          "," + item.lat + "," + item.lon
      };
    });
}

// =====================================================
// 사용자 입력 주소 → 좌표 변환
// 카카오 주소검색 API 사용
// =====================================================
async function geocodeAddress(address, kakaoKey) {
  const apiUrl = new URL("https://dapi.kakao.com/v2/local/search/address.json");
  apiUrl.searchParams.set("query", address);

  const response = await fetch(apiUrl.toString(), {
    headers: {
      Authorization: `KakaoAK ${kakaoKey}`
    }
  });

  const text = await response.text();

  if (!response.ok) {
    return {
      ok: false,
      status: response.status,
      error: text
    };
  }

  const data = JSON.parse(text);
  const documents = data.documents || [];

  if (documents.length === 0) {
    return {
      ok: false,
      status: 404,
      error: "주소 검색 결과가 없습니다."
    };
  }

  const item = documents[0];

  return {
    ok: true,
    address_name: item.address_name,
    road_address_name: item.road_address?.address_name || "",
    lon: Number(item.x),
    lat: Number(item.y)
  };
}

function getNearbyPageHtml() {
  return `<!doctype html>
<html lang="ko">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>가까운 무더위ㆍ한파 쉼터 찾기</title>

  <style>
    body {
      margin: 0;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: #f3f4f6;
      color: #111827;
    }

    .wrap {
      max-width: 720px;
      margin: 0 auto;
      padding: 20px;
    }

    .card {
      background: #ffffff;
      border-radius: 16px;
      padding: 18px;
      margin-bottom: 14px;
      box-shadow: 0 8px 24px rgba(15, 23, 42, 0.08);
    }

    h1 {
      margin: 0 0 10px;
      font-size: 22px;
    }

    p {
      line-height: 1.5;
      color: #4b5563;
    }

    button {
      width: 100%;
      border: 0;
      border-radius: 12px;
      padding: 14px 16px;
      background: #2563eb;
      color: white;
      font-size: 16px;
      font-weight: 700;
      cursor: pointer;
    }

    button:disabled {
      background: #9ca3af;
      cursor: not-allowed;
    }

    .branch {
      border-top: 1px solid #e5e7eb;
      padding: 14px 0;
    }

    .branch:first-child {
      border-top: 0;
    }

    .name {
      font-weight: 800;
      font-size: 17px;
      margin-bottom: 5px;
    }

    .distance {
      color: #2563eb;
      font-weight: 700;
      margin-bottom: 6px;
    }

    .meta {
      color: #4b5563;
      font-size: 14px;
      margin-bottom: 4px;
    }

    a {
      display: inline-block;
      margin-top: 8px;
      margin-right: 8px;
      color: #1d4ed8;
      font-weight: 700;
      text-decoration: none;
    }

    .error {
      color: #dc2626;
      font-weight: 700;
    }

    .small {
      font-size: 13px;
      color: #6b7280;
    }  

    .guide-image {
      width: 100%;
      max-width: 680px;
      display: block;
      margin: 14px auto 16px auto;
      border-radius: 14px;  
    }

    .search-box {
      margin-top: 16px;
      padding-top: 14px;
      border-top: 1px solid #e5e7eb;
    }

    .search-title {
      margin: 0 0 8px 0;
      font-size: 15px;
      font-weight: 800;
      color: #111827;
    }

    .search-row {
      display: flex;
      gap: 8px;
      margin-bottom: 8px;
    }

    .search-row input {
      flex: 1;
      min-width: 0;
      padding: 13px 12px;
      border: 1px solid #d1d5db;
      border-radius: 12px;
      font-size: 15px;
      box-sizing: border-box;
    }

    .search-row button {
      width: auto;
      min-width: 74px;
      padding: 13px 14px;
      border-radius: 12px;
      background: #2563eb;
      color: white;
      font-size: 15px;
      font-weight: 700;
    }
  </style>
</head>

<body>
  <div class="wrap">
    <div class="card">
      <h1>가까운 무더위ㆍ한파 쉼터 찾기</h1>
      <p>
        현위치 사용을 허용하면, 현재 위치에서 가까운 무더위ㆍ한파 쉼터를 안내합니다.
      </p>
      <p class="small">
        현위치는 가까운 무더위ㆍ한파 쉼터 안내에만 사용됩니다.
      </p>

      <img
        src="https://raw.githubusercontent.com/h-branch/NH_weather/main/%EB%82%A0%EC%94%A8%EC%A0%95%EB%B3%B4%20%ED%95%9C%EB%88%88%EC%97%90/summer.png"
        alt="무더위ㆍ한파 쉼터 이용 안내"
        class="guide-image"
      >

      <button id="findBtn">현재 위치로 찾기</button>
      <!-- 직접 검색 영역 -->
      <div class="search-box">
        <p class="search-title">지역명으로 찾기</p>

        <div class="search-row">
          <input
            type="text"
            id="searchInput"
            placeholder="예: 강남구, 양재동, 새문안로16"
          >
          <button id="searchBtn" type="button">검색</button>
        </div>

        <p class="small">
          현위치 사용이 어려운 경우, 지역명을 입력해 주세요.
        </p>
      </div>

    <div id="statusBox" class="card" style="display:none;"></div>
    <div id="resultBox" class="card" style="display:none;"></div>
  </div>

  <script>
    const findBtn = document.getElementById("findBtn");
    const statusBox = document.getElementById("statusBox");
    const resultBox = document.getElementById("resultBox");
    const searchInput = document.getElementById("searchInput");
    const searchBtn = document.getElementById("searchBtn");

    searchBtn.addEventListener("click", async function () {
      const keyword = searchInput.value.trim();

      resultBox.style.display = "block";

      if (!keyword) {
        resultBox.innerHTML =
          '<p><strong>검색어를 입력해 주세요.</strong></p>' +
          '<p class="small">예: 강남구, 양재동, 농협</p>';
        return;
      }

      resultBox.innerHTML =
        '<p><strong>검색 중입니다.</strong></p>' +
        '<p class="small">입력한 검색어: ' + keyword + '</p>';

      try {
        const response = await fetch(
          "/api/keyword?keyword=" + encodeURIComponent(keyword) + "&limit=20"
        );

        const data = await response.json();

        if (!data.ok) {
          throw new Error(data.message || "검색에 실패했습니다.");
        }

        renderBranches(data.branches);
      } catch (error) {
        resultBox.innerHTML =
          '<p><strong>검색 중 오류가 발생했습니다.</strong></p>' +
          '<p class="small">' + error.message + '</p>';
      }
    });

    searchInput.addEventListener("keydown", function (event) {
      if (event.key === "Enter") {
        searchBtn.click();
      }
    });

    function showStatus(message, isError = false) {
      statusBox.style.display = "block";
      statusBox.innerHTML = isError
        ? '<p class="error">' + message + '</p>'
        : '<p>' + message + '</p>';
    }

    function renderBranches(branches) {
      resultBox.style.display = "block";

      if (!branches || branches.length === 0) {
        resultBox.innerHTML = "<p>가까운 무더위ㆍ한파 쉼터를 찾지 못했습니다.</p>";
        return;
      }

      const html = branches.map((b, idx) => {
        const address = b.final_address || b.road_address || b.jibun_address || "";
        const phoneRaw = String(b.phone || "").trim();
        const phone = phoneRaw || "전화번호 정보 없음";
        const phoneLink = phoneRaw.replace(/[^0-9]/g, "");
        const placeUrl = b.place_url || "";
        const routeUrl = b.kakao_route_url || "";

        return \`
          <div class="branch">
            <div class="name">\${idx + 1}. \${b.name}</div>
            \${b.distance_km !== undefined && b.distance_km !== null
              ? '<div class="distance">현재 위치에서 약 ' + b.distance_km + ' km</div>'
              : ''
            }
            <div class="meta">주소: \${address}</div>
            <div class="meta">전화: \${phone}</div>
            \${phoneLink
              ? '<a href="tel:' + phoneLink + '">전화하기</a>'
              : ''
            }
            \${routeUrl ? '<a href="' + routeUrl + '" target="_blank" rel="noopener">카카오맵 길찾기</a>' : ''}
            \${placeUrl ? '<a href="' + placeUrl + '" target="_blank" rel="noopener">장소 상세보기</a>' : ''}
          </div>
        \`;
      }).join("");

      resultBox.innerHTML = html;
    }

    async function requestNearby(lat, lon) {
      const apiUrl = "/api/nearby?lat=" + encodeURIComponent(lat) +
        "&lon=" + encodeURIComponent(lon) +
        "&limit=3";

      const response = await fetch(apiUrl);
      const data = await response.json();

      if (!data.ok) {
        throw new Error(data.message || "가까운 무더위ㆍ한파 쉼터 검색에 실패했습니다.");
      }

      return data.branches;
    }

    findBtn.addEventListener("click", () => {
      if (!navigator.geolocation) {
        showStatus("이 브라우저에서는 위치정보 기능을 사용할 수 없습니다.", true);
        return;
      }

      findBtn.disabled = true;
      resultBox.style.display = "none";
      showStatus("현재 위치를 확인하는 중입니다.");

      navigator.geolocation.getCurrentPosition(
        async (position) => {
          try {
            const lat = position.coords.latitude;
            const lon = position.coords.longitude;

            showStatus("가까운 무더위ㆍ한파 쉼터를 검색하는 중입니다.");

            const branches = await requestNearby(lat, lon);

            showStatus("검색이 완료되었습니다.");
            renderBranches(branches);
          } catch (error) {
            showStatus(error.message, true);
          } finally {
            findBtn.disabled = false;
          }
        },
        (error) => {
          findBtn.disabled = false;

          if (error.code === error.PERMISSION_DENIED) {
            showStatus("위치정보 사용이 거부되었습니다. 브라우저 위치 권한을 허용해주세요.", true);
          } else if (error.code === error.POSITION_UNAVAILABLE) {
            showStatus("현재 위치를 확인할 수 없습니다.", true);
          } else if (error.code === error.TIMEOUT) {
            showStatus("위치 확인 시간이 초과되었습니다.", true);
          } else {
            showStatus("위치 확인 중 오류가 발생했습니다.", true);
          }
        },
        {
          enableHighAccuracy: true,
          timeout: 10000,
          maximumAge: 60000
        }
      );
    });
  </script>
</body>
</html>`;
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    // =====================================================
    // CORS 사전 요청 처리
    // =====================================================
    if (request.method === "OPTIONS") {
      return new Response(null, {
        headers: {
          "Access-Control-Allow-Origin": "*",
          "Access-Control-Allow-Methods": "GET, OPTIONS",
          "Access-Control-Allow-Headers": "Content-Type"
        }
      });
    }

    // =====================================================
    // 1. 서버 상태 확인
    // =====================================================
    if (url.pathname === "/api/health") {
      return json({
        ok: true,
        message: "NH branch worker is running",
        branch_count: BRANCHES.length
      });
    }

    // =====================================================
    // 키워드 기준 쉼터 검색
    // 예: /api/keyword?keyword=강남구
    // =====================================================
    if (url.pathname === "/api/keyword") {
      const keyword = url.searchParams.get("keyword");
      const limit = Number(url.searchParams.get("limit") || 20);

      if (!keyword) {
        return json({
          ok: false,
          message: "검색어를 입력해 주세요."
        }, 400);
      }

      const branches = searchBranchesByKeyword(keyword, limit);

      return json({
        ok: true,
        search_type: "keyword",
        keyword,
        count: branches.length,
        branches
      });
    }

    // =====================================================
    // 2. 좌표 기준 가까운 농협 검색
    // 예:
    // /api/nearby?lat=37.5657&lon=126.9676
    // /api/nearby?lat=37.5657&lon=126.9676&limit=3
    // =====================================================
    if (url.pathname === "/api/nearby") {
      const lat = Number(url.searchParams.get("lat"));
      const lon = Number(url.searchParams.get("lon"));
      const limit = Number(url.searchParams.get("limit") || 5);

      if (!Number.isFinite(lat) || !Number.isFinite(lon)) {
        return json({
          ok: false,
          message: "lat, lon 값을 넣어주세요.",
          example: "/api/nearby?lat=37.5657&lon=126.9676"
        }, 400);
      }

      const branches = findNearestBranches(lat, lon, limit);

      return json({
        ok: true,
        search_type: "coordinate",
        user_location: {
          lat,
          lon
        },
        branches
      });
    }

    // =====================================================
    // 3. 사용자가 입력한 주소 기준 가까운 농협 검색
    // 예:
    // /api/search?addr=서울 중구 통일로 120
    // /api/search?addr=서울 중구 통일로 120&limit=3
    // =====================================================
    if (url.pathname === "/api/search") {
      const addr = url.searchParams.get("addr");
      const limit = Number(url.searchParams.get("limit") || 5);

      if (!addr) {
        return json({
          ok: false,
          message: "addr 값을 입력해주세요.",
          example: "/api/search?addr=서울 중구 통일로 120"
        }, 400);
      }

      if (!env.KAKAO_REST_API_KEY) {
        return json({
          ok: false,
          message: "KAKAO_REST_API_KEY가 Worker Secret에 등록되어 있지 않습니다."
        }, 500);
      }

      const geocoded = await geocodeAddress(
        addr,
        env.KAKAO_REST_API_KEY
      );

      if (!geocoded.ok) {
        return json({
          ok: false,
          message: "입력한 주소를 좌표로 변환하지 못했습니다.",
          input_address: addr,
          detail: geocoded
        }, 400);
      }

      const branches = findNearestBranches(
        geocoded.lat,
        geocoded.lon,
        limit
      );

      return json({
        ok: true,
        search_type: "address",
        input_address: addr,
        geocoded,
        branches
      });
    }

    // =====================================================
    // 4. 현재 위치 허용 페이지
    // 예:
    // /nearby
    // =====================================================
    if (url.pathname === "/nearby") {
      return new Response(getNearbyPageHtml(), {
        headers: {
          "Content-Type": "text/html; charset=utf-8"
        }
      });
    }

    // =====================================================
    // 4. 기본 안내
    // =====================================================
    return json({
      ok: true,
      message: "무더위ㆍ한파 쉼터 안내 API입니다.",
      available_paths: [
        "/api/health",
        "/api/nearby?lat=37.5657&lon=126.9676",
        "/api/nearby?lat=37.5657&lon=126.9676&limit=3",
        "/api/search?addr=서울 중구 통일로 120",
        "/api/search?addr=서울 중구 통일로 120&limit=3"
      ]
    });
  }
};
